-- Limpiar datos previos
TRUNCATE public.historial_informes RESTART IDENTITY CASCADE;
TRUNCATE public.informes RESTART IDENTITY CASCADE;
TRUNCATE public.categorias RESTART IDENTITY CASCADE;
TRUNCATE public.alumnos RESTART IDENTITY CASCADE;

-- ============================================================
-- PERFILES DEMO (usuarios ya existen en auth.users)
-- ============================================================
ON CONFLICT (id) DO UPDATE SET
  email = EXCLUDED.email,
  nombre = EXCLUDED.nombre,
  apellido = EXCLUDED.apellido,
  rol = EXCLUDED.rol,
  activo = EXCLUDED.activo,
  cursos = EXCLUDED.cursos,
  alumnos_pat = EXCLUDED.alumnos_pat;

